```aether:src/middleware/auth.ts
import { Context, Next } from 'hono';
import { Env, User } from '../types';
import { users } from '../data';

/**
 * A simple authentication middleware that sets a 'currentUser' on the Hono context.
 * In a real application, this would involve token verification, database lookups, etc.
 * For this exercise, it simply picks the first user from the data store.
 */
export const authMiddleware = async (c: Context<Env>, next: Next) => {
  // Simulate authentication: always set user-1 (Alice) as the current user.
  // In a real app, this would come from a JWT, session, etc.
  const currentUser: User | undefined = users.find(u => u.id === 'user-1'); // Alice from Alpha Team

  if (!currentUser) {
    // This should ideally not happen with our mock data, but good for robustness.
    return c.json({ error: 'Authentication failed: User not found' }, 401);
  }

  c.set('currentUser', currentUser);
  await next();
};
```

```aether:src/routes/tasks.ts
import { Hono } from 'hono';
import { Env, Task } from '../types';
import { tasks } from '../data';

// Create a Hono router specifically for task-related routes
export const tasksRouter = new Hono<Env>();

/**
 * GET /tasks
 * Returns all tasks for the current user's team, paginated.
 * Query Params:
 *   - limit: number (default: 10)
 *   - offset: number (default: 0)
 */
tasksRouter.get('/', async (c) => {
  const currentUser = c.get('currentUser'); // Type-safe access thanks to Env

  // Extract and parse query parameters
  const query = c.req.query();
  const limit = Math.max(1, parseInt(query.limit || '10', 10)); // Ensure limit is at least 1
  const offset = Math.max(0, parseInt(query.offset || '0', 10)); // Ensure offset is at least 0

  // Filter tasks by the current user's teamId
  const teamTasks: Task[] = tasks.filter(task => task.teamId === currentUser.teamId);

  // Apply pagination
  const paginatedTasks = teamTasks.slice(offset, offset + limit);

  // Return the paginated tasks and total count
  return c.json({
    data: paginatedTasks,
    meta: {
      total: teamTasks.length,
      limit: limit,
      offset: offset,
    },
  });
});
```

