import { Env } from './types';
import { authMiddleware } from './middleware/auth';
import { tasksRouter } from './routes/tasks';

// Initialize the Hono application with our custom environment type
const app = new Hono<Env>();

// Apply global middleware
app.use('*', authMiddleware); // All routes will use this auth middleware

// Mount the tasks router under the /tasks path
app.route('/tasks', tasksRouter);

// Basic root route for testing
app.get('/', (c) => {
  return c.text('Welcome to the Task API! Try /tasks');
});

